#!/usr/bin/env bash
# workflow-2.sh — 产品/术式选型与知情同意 SOP walkthrough for 医疗美容.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="医疗美容"
WORKFLOW="产品/术式选型与知情同意"

usage() {
  cat <<EOF
workflow-2.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./workflow-2.sh             # interactive
  ./workflow-2.sh --dry-run
  ./workflow-2.sh --json
  ./workflow-2.sh --explain
  ./workflow-2.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "产品/术式选型与知情同意" 工作流。

一句话: 从「方案方向已定」到「选定具体材料/剂量/层次 + 逐项风险书面告知并签署知情同意 + 术前留照」——把医疗+法律双重责任落地。

入门 SOP 共 5 步, 失败模式自检 3 项。

相关心智模型:
  • 医美的第一性是医疗，不是消费: 医疗美容首先是外科与皮肤科的**医疗行为**（可致盲、致残、致死），不是快消品；任何决策的第一约束是安全与合规，不是美学最大化或转化率。
  • 先安全后审美：风险分层判断: 资深人的核心能力不是「打得漂亮」，而是**在安全处提效、在危险处零妥协**——知道哪一步能省、哪一步一步都不能省。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**产品合规验证**：所选填充/肉毒/再生/光电查 NMPA「国械注准」三类证 + 现场拆封正品（热玛吉等手具现场拆封验真）；非「认贵」而是「认证」。 evidence: [T03-S003]"
  "**材料/剂量/层次确定**：按机制选材（玻尿酸可逆 vs 再生类不可逆）、定剂量（肉毒按 U、玻尿酸按支 ml）、定层次（皮内/真皮/皮下/骨膜上/SMAS）。 evidence: [T03-S007]"
  "**逐项风险告知**：把血管栓塞/栓塞致盲/坏死/感染/结节肉芽肿/移位/丁达尔、效果不达预期、维持时长、是否可逆、超说明书用药（如肉毒瘦肩/颈部属 off-label）逐项讲清。 evidence: [T03-S007, T03-S009]"
  "**签署知情同意书**：求美者签字留档（医疗+法律双重留痕），off-label 须特别声明并签字。 evidence: [T03-S001, T03-S007]"
  "**术前标准照留存**：多角度标准位留照入病历，作为效果对比与举证依据（注意：对比图不得用于广告宣传）。 evidence: [T03-S001, T03-S002]"
)
declare -a FAILURE_MODES=(
  "**认贵不认证**：贵≠正品，水货/假货致命。avoid：所有产品先跑 NMPA 国械注准查询 + 现场拆封。"
  "**知情同意走过场**：actionable—不要让求美者在没听懂最坏后果（栓塞致盲）的情况下签字；off-label 不单独告知=高危。"
  "**再生类按玻尿酸预期卖**：actionable—不要对再生针说「即刻见效/能溶就不怕」，PLLA/PCL 不可被透明质酸酶逆转，须书面告知不可逆+缓释。"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "workflow-2-walkthrough"
fi
